import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  Outlet,
  useNavigate, // ✅ added
} from "react-router-dom";
import logo from "./assets/logo.png";
import AIAssistant from "./components/aiassistant.js";
import "./App.css";
import { useState, createContext, useContext } from "react";

const AuthContext = createContext();

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(
    JSON.parse(localStorage.getItem("user")) || null,
  );

  const login = (data) => {
    localStorage.setItem("user", JSON.stringify(data));
    setUser(data);
  };

  const logout = () => {
    localStorage.removeItem("user");
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

const useAuth = () => useContext(AuthContext);

const ProtectedRoute = ({ role }) => {
  const { user } = useAuth();

  if (!user) return <Navigate to="/login" />;
  if (role && user.role !== role) return <Navigate to="/" />;

  return <Outlet />;
};

const Home = ({ setShowLogin }) => {
  const { user } = useAuth();

  const services = [
    "Cleaning",
    "Plumbing",
    "Electrical",
    "Carpentry",
    "Painting",
    "Gardening",
    "Cooking",
    "Car Wash",
    "Pest Control",
    "Event Planning",
  ];

  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [showDropdown, setShowDropdown] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [selectedTask, setSelectedTask] = useState("");

  const handleSearch = (value) => {
    setQuery(value);

    if (!value.trim()) {
      setResults([]);
      setShowDropdown(false);
      return;
    }

    const filtered = services.filter((service) =>
      service.toLowerCase().includes(value.toLowerCase())
    );

    setResults(filtered);
    setShowDropdown(true);
  };

  return (
    <>
      {showForm ? (
        /* ===== BOOKING FORM ===== */
        <div className="booking-form">
          <h2>Book Service</h2>

          <input value={selectedTask} readOnly />
          <input placeholder="Your Name" />
          <input placeholder="Address" />
          <input type="date" />

          <button onClick={() => alert("Task Booked!")}>
            Confirm Booking
          </button>

          <button onClick={() => setShowForm(false)}>Back</button>
        </div>
      ) : (
        <>
          {/* NAVBAR */}
          <nav
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              padding: "1rem",
            }}
            className="navbar"
          >
            <img src={logo} alt="logo" style={{ height: "40px" }} />

            {!user && (
              <button onClick={() => setShowLogin(true)}>
                Login / Register
              </button>
            )}

            {user && user.role === "client" && (
              <button onClick={() => (window.location.href = "/client")}>
                Client Dashboard
              </button>
            )}

            {user && user.role === "tasker" && (
              <button onClick={() => (window.location.href = "/tasker")}>
                Tasker Dashboard
              </button>
            )}

            {user && user.role === "admin" && (
              <button onClick={() => (window.location.href = "/admin")}>
                Admin Dashboard
              </button>
            )}
          </nav>

          {/* HERO */}
          <div className="back">
            <section className="hero">
              <h1>Book trusted help for home tasks</h1>
            </section>
          </div>

          {/* SEARCH */}
          <div className="search">
            <div className="search-inner" style={{ position: "relative" }}>
              <input
                value={query}
                onChange={(e) => handleSearch(e.target.value)}
                onFocus={() => setShowDropdown(true)}
                placeholder="Search tasks..."
              />

              <button
                onClick={() => {
                  if (!query.trim()) return;

                  if (!user) {
                    setShowLogin(true);
                    return;
                  }

                  setSelectedTask(query);
                  setShowForm(true);
                  setShowDropdown(false);
                }}
              >
                Search
              </button>

              {showDropdown && results.length > 0 && (
                <div className="search-dropdown">
                  {results.map((item, i) => (
                    <div
                      key={i}
                      className="dropdown-item"
                      onClick={() => {
                        setQuery(item);
                        setShowDropdown(false);
                      }}
                    >
                      🔍 {item}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="empty"></div>

          {/* SERVICES */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))",
            }}
            className="houseservices"
          >
            <div className="serviceitem">
              <h2>Cleaning</h2>
              <p>Daily or weekly cleaning services for your home.</p>
            </div>

            <div className="serviceitem">
              <h2>Car Repairs</h2>
              <p>Handyman services for repairs and maintenance.</p>
            </div>

            <div className="serviceitem">
              <h2>Gardening</h2>
              <p>Lawn care and gardening services.</p>
            </div>

            <div className="serviceitem">
              <h2>Carpentry</h2>
              <p>Custom carpentry and woodworking services.</p>
            </div>

            <div className="serviceitem">
              <h2>Cooking</h2>
              <p>Private chef or meal preparation services.</p>
            </div>

            <div className="serviceitem">
              <h2>Painting</h2>
              <p>Interior and exterior painting services.</p>
            </div>

            <div className="serviceitem">
              <h2>Plumbing</h2>
              <p>Plumbing repairs and installations.</p>
            </div>

            <div className="serviceitem">
              <h2>Electrical</h2>
              <p>Electrical repairs and installations.</p>
            </div>

            <div className="serviceitem">
              <h2>Car Wash</h2>
              <p>Mobile car wash and detailing services.</p>
            </div>

            <div className="serviceitem">
              <h2>Event Planning</h2>
              <p>Full-service event planning and coordination.</p>
            </div>

            <div className="serviceitem">
              <h2>Pest Control</h2>
              <p>Pest removal and prevention services.</p>
            </div>

            <div className="serviceitem">
              <h2>Browse more Services</h2>
              <p>hjkl</p>
            </div>
          </div>

          {/* WORKING */}
          <div className="working">
            <div className="bg">
              <div className="picture">
                <img src="" alt="" />
              </div>

              <div id="howitworks">
                <h2>How it works</h2>
                <ol>
                  <li>
                    <h3>Choose a Tasker</h3>
                    <p>
                      Browse our marketplace of skilled Taskers and choose the one
                      that fits your needs and budget.
                    </p>
                  </li>

                  <li>
                    <h3>Schedule a Tasker</h3>
                    <p>Schedule your Tasker for a time that works for you.</p>
                  </li>

                  <li>
                    <h3>Chat, Pay, and Review</h3>
                    <p>Chat with your Tasker, pay, and review in one place.</p>
                  </li>
                </ol>
              </div>
            </div>
          </div>

          {/* HELP */}
          <div id="help">
            <h2>Get Help Today</h2>
          </div>

          {/* BUTTONS */}
          <div className="serve">
            <button>Cleaning</button>
            <button>Plumbing Help</button>
            <button>Gardening Services</button>
            <button>Woodworking services</button>
            <button>Electrical repairs</button>
            <button>AutoMobile car wash</button>
            <button>Pest removal</button>
            <button>Event planning</button>
            <button>Cooking</button>
            <button>Car repairs</button>
            <button>House Painting</button>
          </div>

          {/* TRUST */}
          <div className="container">
            <h3>Trusted Services. Guaranteed Satisfaction.</h3>
          </div>

          {/* FOOTER */}
          <footer
            style={{
              textAlign: "center",
              padding: "1rem",
              marginTop: "2rem",
            }}
          >
            © 2024 Taskiva. All rights reserved.
          </footer>
        </>
      )}
    </>
  );
};


function Login({ setShowLogin }) {
  const { login } = useAuth();
  const navigate = useNavigate(); // ✅ FIXED

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("client");

  const handleLogin = async () => {
  try {
    const res = await fetch("http://localhost:5000/api/auth/login", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ email, password }),
    });

    const data = await res.json();

    if (res.ok) {
      let role = "client"; // default

      // 🔥 AUTO ADMIN DETECTION
      if (
        email === "admin@taskiva.com" &&
        password === "admin123"
      ) {
        role = "admin";
      }

      login({ ...data, email, role });

      if (role === "admin") navigate("/admin");
      else navigate("/client");

    } else {
      alert(data.message);
    }
  } catch {
    alert("Error logging in");
  }

  };

  return (
    <>
      <div className="login-wrapper">
      <div className="login-card">

        <h2>Login</h2>

        <button
          className="back-btn"
          onClick={() => setShowLogin(false)}
        >
          ← Back to Home
        </button>

        <input
          type="email"
          placeholder="Email"
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          onChange={(e) => setPassword(e.target.value)}
        />

        <select onChange={(e) => setRole(e.target.value)}>
          <option value="client">Client</option>
          <option value="tasker">Tasker</option>
        </select>

        <button
          className="login-btn"
          onClick={handleLogin}
        >
          Login
        </button>

      </div>
    </div>
    </>
    );
}

const Client = () => <h2>Client Dashboard</h2>
;
const Tasker = () => <h2>Tasker Dashboard</h2>;
const Admin = () => <h2>Admin Dashboard</h2>;

export default function App() {
  const [showLogin, setShowLogin] = useState(false);
  const [showForm, setShowForm] = useState(false);

  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route
            path="/"
            element={
              showLogin ? (
                <Login setShowLogin={setShowLogin} />
              ) : (
                <Home setShowLogin={setShowLogin}   setShowForm={setShowForm}   showForm={showForm}/>
              )
            }
          />
          <Route
            path="/login"
            element={<Login setShowLogin={setShowLogin} />}
          />
          <Route element={<ProtectedRoute role="client" />}>
            <Route path="/client" element={<Client />} />
          </Route>
          <Route element={<ProtectedRoute role="tasker" />}>
            <Route path="/tasker" element={<Tasker />} />
          </Route>
          <Route element={<ProtectedRoute role="admin" />}>
            <Route path="/admin" element={<Admin />} />
          </Route>
        </Routes>

        <AIAssistant />
      </BrowserRouter>
    </AuthProvider>
  );
}
